// IIFE
(function () {
  const guessIWillDieMeme = '';

  const disappointedCricketFanMeme = '';

  const perfectMeme = '';

  const defaultMeme = guessIWillDieMeme;

  console.meme = function() {
    let meme = defaultMeme;
    if (arguments.length === 0) meme = guessIWillDieMeme;
    if (arguments.length === 1) meme = perfectMeme;
    if (arguments.length > 1)   meme = disappointedCricketFanMeme;
    const styles = [
      `background-image: url("data:image/jpeg;base64, ${meme}")`,
      'background-size: contain',
      'background-repeat: no-repeat',
      'padding: 75px', // Adjust padding to match image size
    ].join(';');
    console.log('%c ', styles);
  }
})();
